import pandas as pd
import re

# Read the review data from file
review_file_path = var_functions.query_db:18
with open(review_file_path, 'r') as f:
    reviews = json.load(f)

# Get all businesses that accept credit cards (from earlier query)
businesses_cc = [
    {"business_id": "businessid_49", "description": "Located at 6901 Phelps Rd in Goleta, CA, this facility offers a nurturing environment for young learners, providing a range of services in Education, Elementary Schools, Child Care & Day Care, Local Services, Preschools, and Montessori Schools."},
    {"business_id": "businessid_47", "description": "Located at 9916 Clayton Rd in St. Louis, MO, this establishment offers a wide range of services, including Hair Salons, Beauty & Spas, Hair Stylists, Skin Care, Blow Dry/Out Services, and Makeup Artists."},
    {"business_id": "businessid_88", "description": "Located at 11655 W Executive Dr in Boise, ID, this facility offers enthusiasts a premier destination for Gun/Rifle Ranges, Active Life."},
    {"business_id": "businessid_33", "description": "Located at 9655 E US Hwy 36, Unit H in Avon, IN, this establishment offers a range of services including Nail Salons, Hair Removal, Beauty & Spas, and Waxing."},
    {"business_id": "businessid_92", "description": "Located at 690 W Dekalb Pike in King of Prussia, PA, this business offers a diverse range of services and products in the fields of Cosmetics & Beauty Supply, Cosmetic Dentists, Tanning, Teeth Whitening, Beauty & Spas, Dentists, Shopping, Blow Dry/Out Services, Health & Medical, Spray Tanning, and Hair Salons."}
]

# Create a mapping from business_id to business_ref
# business_id format: businessid_X
# business_ref format: businessref_X
# We need to map businessid_49 -> businessref_49
business_id_to_ref = {}
for business in businesses_cc:
    business_id = business['business_id']
    # Extract the numeric part
    numeric_part = business_id.split('_')[1]
    business_ref = f"businessref_{numeric_part}"
    business_id_to_ref[business_id] = business_ref

# Create a mapping from business_ref to categories
business_ref_to_categories = {}
for business in businesses_cc:
    business_id = business['business_id']
    business_ref = business_id_to_ref[business_id]
    description = business['description']

    # Extract categories from description
    # Look for text after "services in" or "including" or "fields of"
    categories = []

    # Try different patterns to extract categories
    patterns = [
        r'providing a range of services in (.+?)(?:\.|$)',
        r'offers a wide range of services, including (.+?)(?:\.|$)',
        r'offers a range of services including (.+?)(?:\.|$)',
        r'offers a diverse range of services and products in the fields of (.+?)(?:\.|$)',
        r'premier destination for (.+?)(?:,|\.|$)'
    ]

    categories_text = ""
    for pattern in patterns:
        match = re.search(pattern, description, re.IGNORECASE)
        if match:
            categories_text = match.group(1)
            break

    if categories_text:
        # Split by commas and "and"
        # Remove "and" and split by commas
        categories_text = categories_text.replace(' and ', ',')
        # Split and clean each category
        category_list = [cat.strip() for cat in categories_text.split(',') if cat.strip()]
        business_ref_to_categories[business_ref] = category_list
    else:
        business_ref_to_categories[business_ref] = []

# Now process reviews to find ratings for these businesses
business_ratings = {}
for review in reviews:
    business_ref = review.get('business_ref')
    if business_ref in business_ref_to_categories:
        rating = int(review.get('rating', 0))
        if business_ref not in business_ratings:
            business_ratings[business_ref] = []
        business_ratings[business_ref].append(rating)

# Calculate average rating per business
business_avg_rating = {}
for business_ref, ratings in business_ratings.items():
    if ratings:
        business_avg_rating[business_ref] = sum(ratings) / len(ratings)

# Count businesses per category
category_count = {}
category_ratings = {}  # Store all ratings for each category

for business_ref, categories in business_ref_to_categories.items():
    if business_ref in business_avg_rating:
        avg_rating = business_avg_rating[business_ref]
        for category in categories:
            # Clean category name further
            category = category.strip()
            if category:
                category_count[category] = category_count.get(category, 0) + 1
                if category not in category_ratings:
                    category_ratings[category] = []
                category_ratings[category].append(avg_rating)

# Find category with most businesses
if category_count:
    max_category = max(category_count.items(), key=lambda x: x[1])
    max_category_name = max_category[0]
    max_category_count = max_category[1]

    # Calculate average rating for this category
    if max_category_name in category_ratings:
        avg_rating = sum(category_ratings[max_category_name]) / len(category_ratings[max_category_name])
        result = {
            "category": max_category_name,
            "business_count": max_category_count,
            "average_rating": round(avg_rating, 2)
        }
    else:
        result = {
            "category": max_category_name,
            "business_count": max_category_count,
            "average_rating": "No ratings available"
        }
else:
    result = {"error": "No categories found"}

print('__RESULT__:')
print(json.dumps(result))"}

